#include <bits/stdc++.h>
#include <numeric>

/* Initialise infinity with a big number. */
#define INF (1LL << 50)

using namespace std;

/* Pair comparator to compare by the first argument. */
struct PairCompare {
	bool operator()(const pair<long long, long long>& a,
					const pair<long long, long long>& b) const {
		if (a.first < b.first) {
			return true;
		} else if (a.first > b.first) {
			return false;
		} else {
			return a.second < b.second;
		}
	}
};

long long dijkstra(long long n,
				   vector<vector<pair<long long, long long>>>& adj,
				   vector<vector<pair<long long, long long>>>& tele,
				   long long lcm)  {
	/* Set of pairs that have on the first position the number of periods, and
	 the second one the node. The set is sorted by the amount of time taken, 
	 and after by the node itself. */
	set<pair<long long, long long>, PairCompare> distNode;

	/* Vector of distances that store the minimum period until it reaches the
	 node in period modulo lcm. */
	vector<vector<long long>>dist(n, vector<long long>(lcm, INF));

	distNode.insert({0, 0});

	/* Minimum variable to store the result. */
	long long minim = INF;

	/* Continues until no more solution is found (the distances are 
	 minimum). */
	while(!distNode.empty()) {
		auto dN = *(distNode.begin());
		distNode.erase(distNode.begin());

		for (auto pair : adj[dN.second]) {
			/* If a minimum distance is found, the vector of distances is
			 updated, and the node with the total period of time is added
			 in the queue. */
			long long p = (long long)pair.second + dN.first;
			long long node = pair.first;
			if (dist[node][p % lcm] > p) {
				dist[node][p % lcm] = p;
				distNode.insert({p, node});
				/* If a new minimum on the wanted line is */
				if (node == n - 1 && minim > p) {
					minim = p;
				}
			}
		}

		for (auto pair : tele[dN.second]) {
			/* Verify if the teleport is opened based on the period of time
			 taken until this node is reached. */
			if (dN.first % pair.second == 0) {
				/* If the teleport is opened, verify if the distance is
				 minimum, and, if so, insert the total period of time and the
				 node in the set. */
				long long p = 1 + dN.first;
				long long node = pair.first;
				if (dist[node][p % lcm] > p) {
					dist[node][p % lcm] = p;
					distNode.insert({p, node});
					if (node == n - 1 && minim > p) {
						minim = p;
					}
				}
			}
		}
	}

	return minim;
}

int main() {
	freopen("teleportare.in", "r", stdin);
	freopen("teleportare.out", "w", stdout);
	long long n, m, k, u, v, t;
	long long lcm = 1;
	cin >> n >> m >> k;

	/* Vector of vector of pairs that stores the nodes reached from the
	 current node and the time taken for the route. */
	vector<vector<pair<long long, long long>>>adj(n);
	/* Vector of vector of pairs that stores the nodes reached from the
	 current node and the modulo time the route opens. */
	vector<vector<pair<long long, long long>>>tele(n);

	for (long long i = 0; i < m; i++) {
		cin >> u >> v >> t;
		adj[u - 1].push_back({v - 1, t});
		adj[v - 1].push_back({u - 1, t});
	}

	for (long long i = 0; i < k; i++) {
		cin >> u >> v >> t;
		tele[u - 1].push_back({v - 1, t});
		tele[v - 1].push_back({u - 1, t});

		/* Calculate the LCM of all numbers given for the teleports for
		 the second dimension in the vector of vectors of distances. */
		long long maxim = (lcm > t) ? lcm : t;

		while (true) {
			if (maxim % lcm == 0 && maxim % t == 0) {
				lcm = maxim;
				break;
			} else {
				++maxim;
			}
		}
	}

	cout << dijkstra(n, adj, tele, lcm) << '\n';

	return 0;
}

import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.PriorityQueue;

public class Teleportare {
	private static final long INF = 1000000000000000L;
	private static final String FILE_IN = "teleportare.in";
	private static final String FILE_OUT = "teleportare.out";

	private static int N;
	private static int M;
	private static int K;

	private static int lcm(int a, int b) {
		return a * b / gcd(a, b);
	}

	private static int gcd(int a, int b) {
		while (b != 0) {
			int temp = b;
			b = a % b;
			a = temp;
		}
		return a;
	}

	private static long best(int n, List<List<Pair<Integer, Integer>>> edges,
		List<List<Pair<Integer, Integer>>> teleporters, int lcm) {

		List<List<Long>> dp = new ArrayList<>(lcm);
		for (int i = 0; i < lcm; i++) {
			dp.add(new ArrayList<>(Collections.nCopies(n + 1, INF)));
		}
		PriorityQueue<NodeState> priorityQueue = new PriorityQueue<>();
		priorityQueue.add(new NodeState(0, 0, 1));
		dp.get(0).set(1, 0L);
		while (!priorityQueue.isEmpty()) {
			NodeState state = priorityQueue.peek();
			priorityQueue.poll();

			long dist = state.cost;
			int modulo = state.modulo;
			int u = state.node;

			if (u == n) {
				return dist;
			}

			if (dist != dp.get(modulo).get(u)) {
				continue;
			}

			int newModulo = (modulo + 1) % lcm;
			for (Pair<Integer, Integer> teleporter : teleporters.get(u)) {
				int period = teleporter.first;
				int v = teleporter.second;

				if (modulo % period != 0) {
					continue;
				}

				if (dp.get(modulo).get(u) + 1 < dp.get(newModulo).get(v)) {
					dp.get(newModulo).set(v, dp.get(modulo).get(u) + 1);
					priorityQueue.add(new NodeState(dp.get(newModulo).get(v), newModulo, v));
				}
			}

			for (Pair<Integer, Integer> edge : edges.get(u)) {
				int cost = edge.first;
				int v = edge.second;
				newModulo = (modulo + cost) % lcm;
				if (dp.get(modulo).get(u) + cost < dp.get(newModulo).get(v)) {
					dp.get(newModulo).set(v, dp.get(modulo).get(u) + cost);
					priorityQueue.add(new NodeState(dp.get(newModulo).get(v), newModulo, v));
				}
			}
		}
		return INF;
	}

	public static void main(String[] args) throws IOException {
		BufferedReader br = new BufferedReader(new FileReader(FILE_IN));

		String[] NmkString = br.readLine().split(" ");
		N = Integer.parseInt(NmkString[0]);
		M = Integer.parseInt(NmkString[1]);
		K = Integer.parseInt(NmkString[2]);

		List<List<Pair<Integer, Integer>>> edges = new ArrayList<>();
		List<List<Pair<Integer, Integer>>> teleporters = new ArrayList<>();
		for (int i = 0; i <= N; i++) {
			edges.add(new ArrayList<>());
			teleporters.add(new ArrayList<>());
		}

		for (int i = 0; i < M; ++i) {
			String[] abc = br.readLine().split(" ");
			int a = Integer.parseInt(abc[0]);
			int b = Integer.parseInt(abc[1]);
			int c = Integer.parseInt(abc[2]);
			edges.get(a).add(new Pair<>(c, b));
			edges.get(b).add(new Pair<>(c, a));
		}

		int currLcm = 1;
		for (int i = 0; i < K; ++i) {
			String[] abc = br.readLine().split(" ");
			int a = Integer.parseInt(abc[0]);
			int b = Integer.parseInt(abc[1]);
			int c = Integer.parseInt(abc[2]);
			teleporters.get(a).add(new Pair<>(c, b));
			teleporters.get(b).add(new Pair<>(c, a));

			currLcm = lcm(currLcm, c);
		}

		for (int i = 1; i <= N; ++i) {
			Collections.shuffle(edges.get(i));
			Collections.shuffle(teleporters.get(i));
		}

		BufferedWriter bw = new BufferedWriter(new FileWriter(FILE_OUT));
		bw.write(String.valueOf(best(N, edges, teleporters, currLcm)));
		bw.newLine();
		bw.close();
	}
}
